// Busca a Skill ativa do nicho do tenant
const tenant = $input.item.json;
const nicho = tenant.niche;

const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;

const res = await fetch(
  `${SUPABASE_URL}/rest/v1/agent_skills?nicho=eq.${nicho}&status=eq.ativo&select=*&limit=1`,
  { headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${SUPABASE_KEY}` } }
);
const skills = await res.json();

if (!skills || skills.length === 0) {
  // Aciona geração de Skill e usa fallback genérico
  await fetch($env.N8N_SKILL_FACTORY_WEBHOOK, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ nicho, tenant_id: tenant.id })
  }).catch(() => {});

  return [{ json: {
    tenant,
    skill_status: 'fallback_generico',
    skill_context: `NICHO: ${nicho}\nUse estratégias universais de crescimento no Instagram para profissionais do nicho ${nicho} no Brasil.`,
    alerta: `⚠️ Skill para ${nicho} sendo gerada. Usando fallback.`
  }}];
}

const skill = skills[0];
const skillContext = `
═══ SKILL ATIVA: ${skill.display_name} ═══

${skill.skill_header}

PILARES: ${JSON.stringify(skill.pilares)}

MIX: ${JSON.stringify(skill.mix_conteudo)}

HOOKS (amostra): ${skill.hooks_banco.slice(0, 10).join(' | ')}

GAPS COMUNS: ${JSON.stringify(skill.gaps_comuns)}
═══════════════════════════════
`;

return [{ json: { tenant, skill_context: skillContext, skill_data: skill, skill_status: 'ativo' } }];

const trendsRaw = $input.item.json.content[0].text;
let trends;
try {
  trends = JSON.parse(trendsRaw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim());
} catch { trends = { oportunidades_pauta: [], trends_semana: [] }; }
return [{ json: { ...$('Buscar Skill do Nicho').item.json, trends } }];

const stratRaw = $input.item.json.content[0].text;
let estrategia;
try {
  estrategia = JSON.parse(stratRaw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim());
} catch { estrategia = { calendario_semanal: [], pilares: [] }; }
return [{ json: { ...$('Parse Trends').item.json, estrategia } }];

// Executa Copywriter + Scripter em paralelo (Promise.all)
const data = $input.item.json;
const ANTHROPIC_KEY = $env.ANTHROPIC_API_KEY;

async function callAgent(system, userContent, maxTokens = 2000) {
  const res = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {
      'anthropic-version': '2023-06-01',
      'x-api-key': ANTHROPIC_KEY,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      model: 'claude-sonnet-4-20250514',
      max_tokens: maxTokens,
      system,
      messages: [{ role: 'user', content: userContent }]
    })
  });
  const json = await res.json();
  return json.content[0].text;
}

const copySystem = `Você é o Copywriter Agent do NexoOmnix, especializado em copy para profissionais autônomos e pequenas empresas no mercado brasileiro. Escreva legendas, hooks, CTAs prontos para publicação. Use a Skill do nicho. Retorne APENAS JSON: { cliente, segmento, posts: [{ dia, tema, formato, hook, legenda_completa, cta, hashtags }], tom_aplicado }`;

const scriptSystem = `Você é o Scripter Agent do NexoOmnix, roteirista especializado em Reels para profissionais brasileiros. Crie roteiros cena-a-cena com hooks virais, scripts de voz com marcações e prompts AI em inglês. Retorne APENAS JSON: { cliente, segmento, reels: [{ titulo, duracao_total, hook_visual, cenas: [{ numero, tempo, tipo, visual, texto_tela, voz, prompt_ai }], roteiro_voz_completo, talking_object }] }`;

const inputStr = JSON.stringify({
  tenant: data.tenant,
  skill_context: data.skill_context,
  calendario: data.estrategia?.calendario_semanal ?? []
});

const [copyRaw, scriptRaw] = await Promise.all([
  callAgent(copySystem, 'Gere as legendas da semana para: ' + inputStr),
  callAgent(scriptSystem, 'Gere os roteiros da semana para: ' + inputStr, 3000)
]);

function parseJSON(raw) {
  try { return JSON.parse(raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim()); }
  catch { return {}; }
}

return [{ json: { ...data, copy: parseJSON(copyRaw), scripts: parseJSON(scriptRaw) } }];
